    const API_KEYS = [
      process.env.ALPHA_VANTAGE_API_KEY,
      process.env.FMP_CLOUD_API_KEY,
    ];
    const BASE_URL = 'https://www.alphavantage.co/query?function=INCOME_STATEMENT&symbol=';
    const FMP_BASE_URL = 'https://financialmodelingprep.com/api/v3/income-statement/';

    export const fetchIncomeStatement = async (symbol = 'AAPL') => {
      let data = null;
      let error = null;

      for (const apiKey of API_KEYS) {
        if (!apiKey) continue; // Skip if API key is not defined

        const url = `${BASE_URL}${symbol}&apikey=${apiKey}`;
        const fmpUrl = `${FMP_BASE_URL}${symbol}?apikey=${apiKey}`;

        try {
          const response = await fetch(url);
          const fmpResponse = await fetch(fmpUrl);

          if (!response.ok) {
            throw new Error(`Alpha Vantage API failed with status ${response.status}`);
          }
          if (!fmpResponse.ok) {
            throw new Error(`FMP API failed with status ${fmpResponse.status}`);
          }
          const alphaData = await response.json();
          const fmpData = await fmpResponse.json();

          if (alphaData.Note || fmpData.message) {
            console.warn(`API Rate Limit: ${apiKey}`);
            continue; // Skip to next API key if rate limited or invalid response
          }

          // Merge or process the data from both APIs as needed.
          data = processAlphaVantageData(alphaData);
          const fmpProcessedData = processFMPData(fmpData);

          // Return both alpha and FMP processed Data
          return { ...data, ...fmpProcessedData };
        } catch (err) {
          console.error(`Error fetching data with key ${apiKey}:`, err);
          error = err.message;
        }
      }

      if (error) {
        throw new Error(error);
      }

      return data; // Return data if available even if some errors occurred
    };

    const processAlphaVantageData = (data) => {
      if (!data || !data['annualReports'] || !data['quarterlyReports']) {
        return { annualReports: [], quarterlyReports: [] };
      }

      const annualReports = data['annualReports'].map(report => ({
